parameters.jsCode:
const data = $('Route by State').first().json;
const text = data.text.trim();
let emoji = ':robot_face:';
let isSkip = (text.toLowerCase() === 'skip');

if (!isSkip) {
  const match = text.match(/:([\w+-]+):/);
  if (match) {
    emoji = match[0];
  } else {
    isSkip = true;
  }
}

let confirmText;
if (isSkip) {
  confirmText = "No problem \u2014 I'll use :robot_face: for now. You can always change it later with \"emoji :your_pick:\".";
} else {
  confirmText = "Done \u2014 I'll use " + emoji + " as my icon from now on.";
}
confirmText += "\n\nHere's what I'll do:\n\u2022 *Every morning* \u2014 I'll send you a quick briefing on what needs attention in your pipeline\n\u2022 *Before meetings* \u2014 I'll prep everything you need to know about the account and attendees\n\u2022 *When deals go quiet* \u2014 I'll draft re-engagement emails for you to review and send\n\nYour first briefing arrives tomorrow at 6am. Type *help* anytime to see what I can do.";

return [{ json: { ...data, capturedEmoji: emoji, confirmText } }];

const data = $('Route by State').first().json;
const newName = data.text.substring(7).trim();
if (!newName) return [{ json: { ...data, newName: data.assistantName, responseText: 'Please provide a name. Usage: *rename [name]*' } }];
return [{ json: { ...data, newName, responseText: 'Done. I\'m ' + newName + ' now.\n\n(Change my name with \"rename [name]\" or my icon with \"emoji [:emoji:]\")' } }];

const data = $('Route by State').first().json;
const input = data.text.substring(6).trim();
const match = input.match(/:([\w+-]+):/);
const newEmoji = match ? match[0] : null;
if (!newEmoji) return [{ json: { ...data, newEmoji: data.assistantEmoji, responseText: 'Please provide an emoji. Usage: *emoji :rocket:*' } }];
return [{ json: { ...data, newEmoji, responseText: 'Done \u2014 I\'ll use ' + newEmoji + ' as my icon from now on.' } }];

const data = $('Route by State').first().json;
const newPersona = data.text.substring(8).trim();
if (!newPersona) return [{ json: { ...data, newPersona: '', responseText: 'Please provide a persona. Usage: *persona casual and witty*' } }];
return [{ json: { ...data, newPersona, responseText: 'Got it \u2014 my personality is now: *' + newPersona + '*\n\nThis changes how I write your briefings and responses. Want to tweak it? Just say \"persona [new description]\".' } }];

const data = $('Route by State').first().json;
let text = '';
const r = data.subRoute;
const name = data.assistantName || 'Your Assistant';
const emoji = data.assistantEmoji || ':robot_face:';

if (r === 'help') {
  // --- Conversation-first help ---
  text = "*Just ask me anything* \u2014 I have access to your People.ai CRM data and can answer questions about accounts, deals, engagement, and pipeline.\n\n" +
    "Try things like:\n" +
    "\u2022 _\"What's happening with AMD?\"_\n" +
    "\u2022 _\"Who should I be talking to at Cisco?\"_\n" +
    "\u2022 _\"Draft a follow-up for my Intel meeting\"_\n" +
    "\u2022 _\"I need a presentation on Q1 results\"_\n\n" +
    ":thread: Reply in a thread to keep the conversation going.\n\n" +
    "*Shortcuts:*\n" +
    "`brief` \u00b7 `meet` \u00b7 `insights` \u00b7 `presentation` \u00b7 `bbr` \u00b7 `stakeholders` \u00b7 `followup` \u00b7 `silence`\n" +
    "`rename` \u00b7 `emoji` \u00b7 `persona` \u00b7 `scope` \u00b7 `focus`\n" +
    "`tips` \u00b7 `announcements`\n\n" +
    "Type `more <shortcut>` for details on any command (e.g. `more brief`).";

} else if (r === 'more_help') {
  // --- Detailed help for a specific shortcut ---
  const target = (data.text || '').toLowerCase().replace(/^(more|help)\s+/, '').trim();

  const details = {
    'silence': "*`silence` \u2014 Silence Contract Check*\n\n" +
      "Check your accounts for engagement gaps right now.\n\n" +
      "I'll scan your accounts (based on your ownership and CSM assignments) and report any that have gone quiet \u2014 no emails, meetings, or calls in 5+ days.\n\n" +
      "*Severity levels:*\n" +
      "\u2022 :large_blue_circle: Getting quiet (5-9 days)\n" +
      "\u2022 :warning: Gone silent (10-20 days)\n" +
      "\u2022 :red_circle: Relationship at risk (21+ days)\n\n" +
      "The daily cron also runs this automatically at 6:30am PT.",
    'brief': "*`brief` \u2014 On-Demand Sales Digest*\n\n" +
      "Get an instant sales briefing, just like your morning digest.\n\n" +
      "*Usage:*\n" +
      "\u2022 `brief` \u2014 today's themed digest\n" +
      "\u2022 `brief risk` \u2014 deals that need attention\n" +
      "\u2022 `brief momentum` \u2014 deals picking up speed\n" +
      "\u2022 `brief engagement` \u2014 engagement shifts\n" +
      "\u2022 `brief full` \u2014 full pipeline review\n" +
      "\u2022 `brief review` \u2014 weekly recap\n\n" +
      "You can also use day names: `brief monday`, `brief friday`\n\n" +
      "_Or just ask naturally: \"give me a briefing on at-risk deals\"_",
    'meet': "*`meet` \u2014 On-Demand Meeting Prep*\n\n" +
      "Get an instant meeting brief for any account.\n\n" +
      "*Usage:*\n" +
      "\u2022 `meet Five9` \u2014 prep for Five9\n" +
      "\u2022 `prep Dataiku` \u2014 same thing\n" +
      "\u2022 `meeting brief IBM` \u2014 longer form\n\n" +
      "_Researches the account, contacts, engagement, and deals via People.ai._",

    'insights': "*`insights` \u2014 Pipeline Intelligence*\n\n" +
      "Deep analysis of your pipeline with actionable recommendations.\n\n" +
      "*Usage:*\n" +
      "\u2022 `insights` \u2014 full pipeline analysis\n" +
      "\u2022 `insights stalled` \u2014 deals that have gone quiet\n" +
      "\u2022 `insights risk` \u2014 deals showing warning signs\n" +
      "\u2022 `insights hidden` \u2014 ghost opportunities\n" +
      "\u2022 `insights accelerating` \u2014 fast-moving deals\n\n" +
      "_Or just ask naturally: \"show me insights on stalled deals\"_",

    'presentation': "*`presentation` \u2014 Create a Presentation*\n\n" +
      "Generate a Backstory-branded Google Slides deck on any topic.\n\n" +
      "*Usage:*\n" +
      "\u2022 `presentation Q1 engineering review for Cisco`\n" +
      "\u2022 `presentation competitive landscape for AMD`\n" +
      "\u2022 `presentation onboarding progress for Acme`\n\n" +
      "I'll pull data from People.ai and build the slides. Takes about 2 minutes.\n\n" +
      "_Or just ask naturally: \"I need a presentation on MCP for AMD\"_",

    'bbr': "*`bbr` \u2014 Business Review Presentation*\n\n" +
      "Generate a complete Backstory Business Review (BBR) deck for a customer account.\n\n" +
      "*Usage:*\n" +
      "\u2022 `bbr AMD`\n" +
      "\u2022 `pbr Cisco` (same thing)\n\n" +
      "Includes: engagement scores, open opps, key contacts, activity trends, adoption signals, and a roadmap placeholder.\n\n" +
      "_Or just ask naturally: \"create a business review for AMD\"_",

    'stakeholders': "*`stakeholders` \u2014 Stakeholder Map*\n\n" +
      "See who you're engaging at an account, who's gone quiet, and where you have coverage gaps.\n\n" +
      "*Usage:*\n" +
      "\u2022 `stakeholders AMD`\n" +
      "\u2022 `stakeholders Cisco`\n\n" +
      "Shows: active contacts with engagement trends, silent contacts, missing roles, and a recommendation for who to re-engage.\n\n" +
      "_Or just ask naturally: \"who should I be talking to at AMD?\"_",

    'followup': "*`followup` \u2014 Draft Follow-up Email*\n\n" +
      "Draft a follow-up email after a customer meeting.\n\n" +
      "*Usage:*\n" +
      "\u2022 `followup AMD`\n" +
      "\u2022 `followup Cisco`\n" +
      "\u2022 `follow-up Intel`\n\n" +
      "I'll find your most recent meeting with the account, check the deal context, and draft a professional follow-up with next steps.\n\n" +
      "_Or just ask naturally: \"draft a follow-up for my AMD meeting\"_",

    'rename': "*`rename` \u2014 Change My Name*\n\n" +
      "Give me a new name that appears on all my messages.\n\n" +
      "*Usage:*\n" +
      "\u2022 `rename Luna`\n" +
      "\u2022 `rename ScottAI`\n" +
      "\u2022 `rename Jarvis`",

    'emoji': "*`emoji` \u2014 Change My Icon*\n\n" +
      "Pick a Slack emoji that appears next to my name.\n\n" +
      "*Usage:*\n" +
      "\u2022 `emoji :rocket:`\n" +
      "\u2022 `emoji :star:`\n" +
      "\u2022 `emoji :brain:`",

    'persona': "*`persona` \u2014 Change My Personality*\n\n" +
      "Adjust how I communicate with you.\n\n" +
      "*Usage:*\n" +
      "\u2022 `persona friendly and uses sports metaphors`\n" +
      "\u2022 `persona formal and data-driven`\n" +
      "\u2022 `persona witty and casual`\n" +
      "\u2022 `persona short responses for busy professionals`",

    'scope': "*`scope` \u2014 Change Briefing Scope*\n\n" +
      "Control whose deals appear in your morning digest.\n\n" +
      "*Usage:*\n" +
      "\u2022 `scope my_deals` \u2014 just your own opportunities (IC mode)\n" +
      "\u2022 `scope team_deals` \u2014 your direct reports' deals (Manager mode)\n" +
      "\u2022 `scope top_pipeline` \u2014 top pipeline deals across the org (Exec mode)",

    'focus': "*`focus` \u2014 Set Digest Focus Area*\n\n" +
      "Prioritize a specific area in your morning briefings.\n\n" +
      "*Usage:*\n" +
      "\u2022 `focus retention` \u2014 renewals and churn risk\n" +
      "\u2022 `focus revenue` \u2014 pipeline and revenue targets\n" +
      "\u2022 `focus technical` \u2014 technical adoption signals\n" +
      "\u2022 `focus executive` \u2014 strategic overview",

    'tips': "*Feature Tips*\n\n" +
      "I\u2019ll share helpful tips about features you haven\u2019t tried yet \u2014 delivered at most twice a week.\n\n" +
      "*Commands:*\n" +
      "\u2022 `stop tips` \u2014 pause feature tips\n" +
      "\u2022 `resume tips` \u2014 resume feature tips",

    'announcements': "*Feature Announcements*\n\n" +
      "I\u2019ll let you know when I learn new capabilities.\n\n" +
      "*Commands:*\n" +
      "\u2022 `stop announcements` \u2014 pause announcements\n" +
      "\u2022 `resume announcements` \u2014 resume announcements",

  };

  // Also accept aliases
  const aliases = { 'pbr': 'bbr', 'digest': 'brief',
    'silent': 'silence', 'silent accounts': 'silence', 'silence check': 'silence', 'briefing': 'brief', 'slide': 'presentation', 'slides': 'presentation', 'deck': 'presentation', 'name': 'rename', 'icon': 'emoji', 'stop tips': 'tips', 'pause tips': 'tips', 'resume tips': 'tips', 'start tips': 'tips', 'stop announcements': 'announcements', 'resume announcements': 'announcements', 'start announcements': 'announcements', 'follow-up': 'followup', 'contacts': 'stakeholders', 'people': 'stakeholders', 'follow-up': 'followup', 'contacts': 'stakeholders', 'people': 'stakeholders', 'prep': 'meet', 'meeting brief': 'meet', 'meeting prep': 'meet' };
  const resolved = aliases[target] || target;

  if (details[resolved]) {
    text = details[resolved];
  } else {
    text = "I don't have detailed help for `" + target + "`.\n\n" +
      "Available shortcuts: `brief` \u00b7 `meet` \u00b7 `insights` \u00b7 `presentation` \u00b7 `bbr` \u00b7 `stakeholders` \u00b7 `followup`\n" +
      "`rename` \u00b7 `emoji` \u00b7 `persona` \u00b7 `scope` \u00b7 `focus` \u00b7 `tips` \u00b7 `announcements`\n\n" +
      "Type `more <shortcut>` for details on any of these.";
  }

} else if (r === 'stop_digest') {
  text = "Understood. I\u2019ve paused your morning briefings.\n\nI\u2019ll still prep you before meetings and flag urgent risks. Just type `resume digest` whenever you want them back.";
} else if (r === 'resume_digest') {
  text = "Morning briefings are back on. You\u2019ll get the next one tomorrow at 6am.";
} else if (r === 'stop_tips') {
  text = "Tips paused \u2014 I won\u2019t send feature tips anymore. Type `resume tips` anytime to restart.";
} else if (r === 'resume_tips') {
  text = "Tips resumed! I\u2019ll share helpful feature tips from time to time.";
} else if (r === 'stop_announcements') {
  text = "Announcements paused \u2014 I won\u2019t send new feature announcements. Type `resume announcements` anytime to restart.";
} else if (r === 'resume_announcements') {
  text = "Announcements resumed! I\u2019ll let you know when I learn new tricks.";
} else if (r === 'stop_briefs') {
  text = "Meeting briefs paused \u2014 I won\u2019t send pre-meeting prep anymore. Type `start briefs` anytime to resume.";
} else if (r === 'resume_briefs') {
  text = "Meeting briefs are back on! I\u2019ll prep you before upcoming customer meetings.";
} else {
  text = "I didn\u2019t catch that. You can ask me anything about your accounts and deals, or try:\n\n" +
    "`brief` \u00b7 `meet` \u00b7 `insights` \u00b7 `presentation` \u00b7 `bbr` \u00b7 `stakeholders` \u00b7 `followup` \u00b7 `help`";
}

const needsUpdate = (r === 'stop_digest' || r === 'resume_digest');
const digestEnabled = (r === 'resume_digest');

// Education preference updates (tips_enabled, announcements_enabled)
const needsBriefsUpdate = (r === 'stop_briefs' || r === 'resume_briefs');
const meetingPrepEnabled = (r === 'resume_briefs');
const needsEducationUpdate = ['stop_tips', 'resume_tips', 'stop_announcements', 'resume_announcements'].includes(r);
let educationField = null;
let educationValue = null;
if (r === 'stop_tips') { educationField = 'tips_enabled'; educationValue = false; }
else if (r === 'resume_tips') { educationField = 'tips_enabled'; educationValue = true; }
else if (r === 'stop_announcements') { educationField = 'announcements_enabled'; educationValue = false; }
else if (r === 'resume_announcements') { educationField = 'announcements_enabled'; educationValue = true; }

return [{ json: { ...data, responseText: text, needsUpdate, digestEnabled, needsBriefsUpdate, meetingPrepEnabled, needsEducationUpdate, educationField, educationValue } }];

// Extract department and division from Slack custom profile fields
// Called after Get Slack User Info, passes data to Create User Record
const slackResponse = $('Get Slack User Info').first().json;
const fieldMeta = $('Get Onboarding Profile Fields').first().json;

const user = slackResponse.user || {};
const profile = user.profile || {};
const fields = profile.fields || {};

// Build label→ID map from workspace field metadata
const profileFields = (fieldMeta.profile && fieldMeta.profile.fields) || [];
const labelToId = {};
for (const f of profileFields) {
  if (f.label) {
    labelToId[f.label.toLowerCase()] = f.id;
  }
}

function getCustomField(label) {
  const fieldId = labelToId[label.toLowerCase()];
  if (fieldId && fields[fieldId]) {
    return fields[fieldId].value || '';
  }
  return '';
}

// Try custom fields first, fall back to standard fields
const department = getCustomField('Department') || profile.department || '';
const division = getCustomField('Division') || profile.title || '';

// Derive digest_scope
function deriveDigestScope(div) {
  if (!div) return 'my_deals';
  const lower = div.toLowerCase();
  if (/^(vp|svp|evp|cro|chief|head of)/.test(lower)) return 'top_pipeline';
  if (/(manager|director)/.test(lower)) return 'team_deals';
  return 'my_deals';
}

const digestScope = deriveDigestScope(division);

return [{
  json: {
    ...slackResponse,
    extractedDepartment: department,
    extractedDivision: division,
    derivedDigestScope: digestScope
  }
}];

const input = $('Route by State').first().json;
const assistantName = input.assistantName;
const assistantEmoji = input.assistantEmoji;
const currentScope = (input.userRecord && input.userRecord.digest_scope) || 'my_deals';

// Slack auto-converts emails to <mailto:email@domain|email@domain> in Events API payloads.
// Strip that formatting to get the raw email back.
function extractEmail(str) {
  const slackMailto = str.match(/<mailto:([^|>]+)\|[^>]*>/i);
  if (slackMailto) return slackMailto[1].trim();
  const slackAngle = str.match(/<([^|>]+@[^|>]+)>/);
  if (slackAngle) return slackAngle[1].trim();
  return str.trim();
}

// Use raw text (preserve case) but strip Slack formatting first
const rawText = extractEmail((input.text || '').trim());
const scopeArgRaw = extractEmail(rawText.replace(/^scope\s*/i, '').trim());
const scopeArg = scopeArgRaw.toLowerCase();

const scopeMap = {
  'my deals': 'my_deals', 'my_deals': 'my_deals', 'deals': 'my_deals',
  'personal': 'my_deals', 'me': 'my_deals', 'ic': 'my_deals',
  'team': 'team_deals', 'team_deals': 'team_deals', 'my team': 'team_deals', 'team deals': 'team_deals',
  'pipeline': 'top_pipeline', 'top_pipeline': 'top_pipeline', 'top pipeline': 'top_pipeline',
  'full pipeline': 'top_pipeline', 'exec': 'top_pipeline', 'executive': 'top_pipeline', 'all': 'top_pipeline'
};

const scopeLabels = {
  'my_deals': 'My Deals — your personal pipeline',
  'team_deals': 'Team — your team\'s pipeline',
  'top_pipeline': 'Full Pipeline — org-wide top deals'
};

function emailToDisplayName(email) {
  return email.split('@')[0]
    .replace(/\./g, ' ')
    .replace(/\b\w/g, c => c.toUpperCase());
}

let newScope = null;
let responseText = '';

if (!scopeArg || scopeArg === 'scope') {
  // Just "scope" — show current setting
  let currentLabel;
  if (currentScope.startsWith('person:')) {
    const targetEmail = currentScope.replace('person:', '');
    currentLabel = emailToDisplayName(targetEmail) + "'s pipeline";
  } else {
    currentLabel = scopeLabels[currentScope] || currentScope;
  }
  responseText = `${assistantEmoji} Your briefing scope is currently set to: *${currentLabel}*\n\nTo change it:\n\u2022 \`scope me\` \u2014 your personal pipeline\n\u2022 \`scope team\` \u2014 your team's pipeline\n\u2022 \`scope pipeline\` \u2014 full org pipeline\n\u2022 \`scope name@company.com\` \u2014 a specific person's deals`;

} else if (scopeArgRaw.includes('@')) {
  // Full email address — scope to a specific person's deals
  const targetEmail = scopeArgRaw.toLowerCase();
  newScope = 'person:' + targetEmail;
  const displayName = emailToDisplayName(targetEmail);

  if (newScope === currentScope) {
    responseText = `${assistantEmoji} Your briefing is already scoped to *${displayName}*'s pipeline. No changes needed!`;
    newScope = null;
  } else {
    responseText = `${assistantEmoji} Got it \u2014 I'll show you *${displayName}*'s pipeline in your next digest.\n\nType \`scope me\` to switch back to your own deals.`;
  }

} else if (scopeMap[scopeArg]) {
  newScope = scopeMap[scopeArg];
  if (newScope === currentScope) {
    responseText = `${assistantEmoji} Your briefing scope is already set to *${scopeLabels[currentScope]}*. No changes needed!`;
    newScope = null;
  } else {
    responseText = `${assistantEmoji} Got it! Your briefing scope is now set to *${scopeLabels[newScope]}*.\n\nYour next morning digest will use this view.`;
  }

} else {
  responseText = `${assistantEmoji} I didn\u2019t recognize that scope. Try one of:\n\u2022 \`scope me\` \u2014 your personal pipeline\n\u2022 \`scope team\` \u2014 your team's pipeline\n\u2022 \`scope pipeline\` \u2014 full org pipeline\n\u2022 \`scope name@company.com\` \u2014 a specific person's deals`;
}

return [{
  json: {
    userId: input.dbUserId,
    channelId: input.channelId,
    newScope,
    needsUpdate: !!newScope,
    responseText,
    assistantName,
    assistantEmoji
  }
}];

const data = $('Route by State').first().json;
