  'technical': 'technical', 'se': 'technical', 'solutions': 'technical', 'poc': 'technical', 'engineering': 'technical',
  'executive': 'executive', 'exec': 'executive', 'leadership': 'executive', 'strategic': 'executive', 'ceo': 'executive'
};

const focusLabels = {
  'revenue':   'Revenue — new logo & net new ARR',
  'retention': 'Retention — renewals & existing customers',
  'technical': 'Technical — POC stage & SE view',
  'executive': 'Executive — strategic portfolio overview'
};

let newFocus = null;
let needsUpdate = false;
