if (!focusArg || focusArg === 'status' || focusArg === 'show' || focusArg === '?') {
  responseText = `Your current briefing focus is *${focusLabels[currentFocus] || currentFocus}*.\n\nChange it with:\n• \`focus revenue\` — new logo and net new ARR\n• \`focus retention\` — renewals and existing customers only\n• \`focus technical\` — POC stage and SE view\n• \`focus executive\` — strategic portfolio overview`;
} else {
