parameters.jsCode:
// Parse account name from meet command + build People.ai query
const data = $('Route by State').first().json;
const text = (data.text || '').trim();

// Strip command keywords to find the account name
const accountArg = text
  .replace(/\b(meet|meeting\s+brief|prep|prep\s+me\s+for|for|with|about|on|a|the|my|please)\b/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim();

if (!accountArg) {
  return [{ json: { ...data, hasAccount: false, responseText: 'What account should I prep you for? Try: `meet Five9` or `meet Dataiku`' } }];
}

const ur = data.userRecord || {};
const repName = (ur.email || '').split('@')[0].replace(/\./g, ' ').replace(/\b\w/g, c => c.toUpperCase()) || 'Rep';

// Build People.ai export query for meetings at this account in next 48h
const now = Date.now();
const twoDaysOut = now + 48 * 3600000;
const meetQuery = JSON.stringify({
  object: "activity",
  filter: {
    "$and": [
      { attribute: { slug: "ootb_activity_type" }, clause: { "$eq": "meeting" } },
      { attribute: { slug: "ootb_activity_external" }, clause: { "$eq": true } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$gte": now - 24 * 3600000 } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$lte": twoDaysOut } }
    ]
  },
  columns: [
    { slug: "ootb_activity_uid" },
    { slug: "ootb_activity_timestamp" },
    { slug: "ootb_activity_subject" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_email" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_name" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_external" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_job_title" },
    { slug: "ootb_activity_account" },
    { slug: "ootb_activity_opportunity" }
  ],
  sort: [
    { attribute: { slug: "ootb_activity_timestamp" }, direction: "asc" }
  ]
});

return [{ json: {
  ...data,
  hasAccount: true,
  accountName: accountArg,
  repName,
  meetQuery,
  meetInput: {
    userId: data.dbUserId,
    slackUserId: data.userId,
    email: ur.email || '',
    assistant_name: data.assistantName,
    assistant_emoji: data.assistantEmoji,
    assistant_persona: ur.assistant_persona || null,
    timezone: ur.timezone || 'America/Los_Angeles',
    repName,
    accountName: accountArg,
    meetingSubject: 'On-demand meeting prep: ' + accountArg,
    meetingTime: '',
    participants: '',
    opportunityName: '',
    opportunityStage: '',
    opportunityAmount: '',
    opportunityCloseDate: '',
    opportunityEngagement: '',
    activityUid: 'ondemand_' + Date.now()
  }
} }];

// Parse People.ai participant CSV and enrich meetInput
const data = $('Parse Meet Account').first().json;
const meetInput = { ...data.meetInput };
const accountName = (data.accountName || '').toLowerCase();

// Get the CSV from Fetch Meet Participants
const raw = $('Fetch Meet Participants').first().json;
const csvData = typeof raw === 'string' ? raw : (raw.data || raw.body || '');

if (!csvData || typeof csvData !== 'string') {
  // No participant data — proceed without it
  return [{ json: meetInput }];
}

function parseCsvLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  let inBrackets = 0;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '[') inBrackets++;
    else if (ch === ']') inBrackets--;
    if (ch === '"') {
      if (inQuotes && i + 1 < line.length && line[i + 1] === '"') {
        current += '"'; i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (ch === ',' && !inQuotes && inBrackets === 0) {
      result.push(current.trim());
      current = '';
    } else {
      current += ch;
    }
  }
  result.push(current.trim());
  return result;
}

function parseList(val) {
  if (!val) return [];
  return val.replace(/^\[/, '').replace(/\]$/, '').trim().split(';').map(s => s.trim());
}

const lines = csvData.split(/\r?\n/).filter(l => l.trim());
if (lines.length < 2) {
  return [{ json: meetInput }];
}

const headers = parseCsvLine(lines[0]);
const headerMap = {};
headers.forEach((h, i) => { headerMap[h.toLowerCase()] = i; });

function getField(row, ...names) {
  for (const name of names) {
    const idx = headerMap[name.toLowerCase()];
    if (idx !== undefined && row[idx]) return row[idx];
  }
  return '';
}

// Find meetings matching this account
const now = Date.now();
let bestMatch = null;
let bestDiff = Infinity;

for (let i = 1; i < lines.length; i++) {
  const row = parseCsvLine(lines[i]);
  if (row.length < 2) continue;

  const acct = getField(row, 'Account (name)', 'Account');
  if (!acct) continue;

  // Fuzzy account matching
  const acctLower = acct.toLowerCase();
  const inputLower = accountName.toLowerCase();

  let isMatch = false;
  if (acctLower === inputLower) isMatch = true;
  else if (acctLower.startsWith(inputLower)) isMatch = true;
  else if (inputLower.startsWith(acctLower)) isMatch = true;
  else if (new RegExp('\\b' + inputLower.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'i').test(acct)) isMatch = true;
  else if (acctLower.includes(inputLower)) isMatch = true;
  else {
    const inputWords = inputLower.split(/\s+/);
    const matched = inputWords.filter(w => acctLower.includes(w));
    if (matched.length > 0 && matched.length >= inputWords.length * 0.5) isMatch = true;
  }

  if (!isMatch) continue;

  const timestampStr = getField(row, 'Activity date');
  const ts = timestampStr ? new Date(timestampStr).getTime() : 0;

  // Prefer the nearest upcoming meeting
  const diff = ts - now;
  if (diff > -3600000 && diff < bestDiff) { // Allow 1hr past meetings too
    bestDiff = diff;
    bestMatch = {
      subject: getField(row, 'Subject') || 'Customer Meeting',
      timestamp: ts,
      timestampStr,
      activityUid: getField(row, 'Activity'),
      emails: parseList(getField(row, 'Activity Participants (Email)')),
      names: parseList(getField(row, 'Activity Participants (Name)')),
      externals: parseList(getField(row, 'Activity Participants (External)')),
      titles: parseList(getField(row, 'Activity Participants (Job Title)')),
      oppName: getField(row, 'Opportunity (name)', 'Opportunity'),
      accountName: getField(row, 'Account (name)', 'Account'),
    };
  }
}

if (bestMatch) {
  // Build a formatted participant string for the agent
  const parts = [];
  for (let p = 0; p < bestMatch.emails.length; p++) {
    const isExternal = (bestMatch.externals[p] || '').toLowerCase() === 'true';
    const name = bestMatch.names[p] || bestMatch.emails[p];
    const title = bestMatch.titles[p] || '';
    const tag = isExternal ? 'external' : 'internal';
    parts.push(`${name} (${tag}${title ? ', ' + title : ''}) <${bestMatch.emails[p]}>`);
  }

  meetInput.participants = parts.join('; ');
  meetInput.meetingSubject = bestMatch.subject;
  meetInput.meetingTime = String(bestMatch.timestamp);
  meetInput.accountName = bestMatch.accountName || data.accountName;
  if (bestMatch.oppName) meetInput.opportunityName = bestMatch.oppName;
  if (bestMatch.activityUid) meetInput.activityUid = bestMatch.activityUid;
}

return [{ json: meetInput }];

const body = $('Slack Events Webhook').first().json.body;
const headers = $('Slack Events Webhook').first().json.headers || {};

// Drop Slack retry deliveries
if (headers['x-slack-retry-num'] && parseInt(headers['x-slack-retry-num']) > 0) {
  return [];
}

const event = body.event || {};

// Layer 1: Classic bot indicators
const hasClassicBotIndicator = !!(event.bot_id || event.subtype || event.bot_profile || event.app_id);

// Layer 2: Self-message check via authorizations
const auths = body.authorizations || [];
const botUserId = auths.length > 0 ? auths[0].user_id : null;
const isSelfMessage = !!(botUserId && event.user === botUserId);

// Layer 3: Text-based bot message detection (stops feedback loops)
const text = (event.text || '').trim();
const isBotText = text.startsWith(':hourglass_flowing_sand:') ||
  text.startsWith('Sorry, I was unable to generate') ||
  text === '';

// Layer 4: No user = non-human event
const noUser = !event.user;

const isBot = hasClassicBotIndicator || isSelfMessage || (isBotText && !event.user) || noUser;

return [{
  json: {
    eventType: event.type,
    channelType: event.channel_type || null,
    userId: event.user,
    channelId: event.channel || null,
    text: text,
    ts: event.ts,
    eventId: body.event_id,
    teamId: body.team_id,
    isBot,
    tab: event.tab || null,
    threadTs: event.thread_ts || null,
    isThreadReply: !!event.thread_ts,
    _debug_botUserId: botUserId,
    _debug_hasClassic: hasClassicBotIndicator,
    _debug_isSelf: isSelfMessage,
    _debug_isBotText: isBotText,
    _debug_eventUser: event.user || null,
    _debug_authCount: auths.length
  }
}];

const event = $('Extract Event Data').first().json;
const user = $('Lookup User').first().json;
const text = event.text;
const userId = event.userId;

let userExists = !!(user && user.id);
let state = userExists ? (user.onboarding_state || 'new') : null;
let route = 'unknown';
let subRoute = 'help';

if (!userExists) {
  route = 'new_user';
} else if (state === 'new') {
  route = 'send_greeting';
} else if (state === 'awaiting_name') {
  route = 'capture_name';
} else if (state === 'awaiting_emoji') {
  route = 'capture_emoji';
} else if (state === 'complete') {
  const lower = text.toLowerCase();

  // --- Pass 1: Exact command matching (keyword at start of text) ---
  if (lower.startsWith('rename ')) route = 'cmd_rename';
  else if (lower.startsWith('emoji ')) route = 'cmd_emoji';
  else if (lower.startsWith('persona ')) route = 'cmd_persona';
  else if (lower === 'scope' || lower.startsWith('scope ')) route = 'cmd_scope';
  else if (lower === 'focus' || lower.startsWith('focus ')) route = 'cmd_focus';
  else if (lower === 'silence' || lower === 'silent' || lower === 'silent accounts' || lower.startsWith('silence check')) {
      route = 'cmd_silence';
    } else if (lower === 'brief' || lower.startsWith('brief ')) route = 'cmd_brief';
  else if (lower === 'meet' || lower.startsWith('meet ') || lower.startsWith('meeting brief ') || lower.startsWith('prep ')) route = 'cmd_meet';
  else if (lower === 'insights' || lower.startsWith('insights ')) route = 'cmd_insights';
  else if (/\b(bbr|pbr)\b/i.test(lower)) route = 'cmd_bbr';
  else if (lower === 'presentation' || lower.startsWith('presentation ')) route = 'cmd_presentation';
  else if (lower === 'stakeholders' || lower.startsWith('stakeholders ')) {
    route = 'cmd_other'; subRoute = 'stakeholders';
  }
  else if (lower === 'followup' || lower.startsWith('followup ') || lower.startsWith('follow-up ') || lower.startsWith('follow up ')) {
    route = 'cmd_other'; subRoute = 'followup';
  }
  else if (lower.startsWith('more ') || (lower.startsWith('help ') && lower !== 'help')) {
    route = 'cmd_other'; subRoute = 'more_help';
  } else {
    // --- Pass 2: Fuzzy keyword matching (keyword anywhere in text) ---
    if (/\b(presentation|slide|slides|deck)\b/.test(lower)) route = 'cmd_presentation';
    else if (/\b(business\s+review)\b/.test(lower)) route = 'cmd_bbr';
    else if (/\b(brief|briefing|digest)\b/.test(lower)) route = 'cmd_brief';
    else if (/\b(meet(?:ing)?\s+(?:brief|prep)|prep\s+(?:me|for))\b/i.test(lower)) route = 'cmd_meet';
    else if (/\binsights?\b/.test(lower)) route = 'cmd_insights';
    else if (/\b(stakeholder|stakeholders|who\s+(should|am|are)\s+I?\s*(be\s+)?talk)/i.test(lower)) {
      route = 'cmd_other'; subRoute = 'stakeholders';
    }
    else if (/\b(follow[\s-]?up|draft\s+(a\s+)?(email|message|note))\b/i.test(lower)) {
      route = 'cmd_other'; subRoute = 'followup';
    }
    else {
      // --- Pass 3: Meta commands and fallback ---
      route = 'cmd_other';
      if (lower === 'stop digest' || lower === 'pause digest') subRoute = 'stop_digest';
      else if (lower === 'resume digest' || lower === 'start digest') subRoute = 'resume_digest';
      else if (lower === 'stop briefs' || lower === 'pause briefs' || lower === 'stop meeting briefs') subRoute = 'stop_briefs';
      else if (lower === 'start briefs' || lower === 'resume briefs' || lower === 'start meeting briefs') subRoute = 'resume_briefs';
      else if (lower === 'stop tips' || lower === 'pause tips') subRoute = 'stop_tips';
      else if (lower === 'resume tips' || lower === 'start tips') subRoute = 'resume_tips';
      else if (lower === 'stop announcements') subRoute = 'stop_announcements';
      else if (lower === 'resume announcements' || lower === 'start announcements') subRoute = 'resume_announcements';
      else if (lower === 'help') subRoute = 'help';
      else subRoute = 'unrecognized';
    }
  }
}

let assistantName = (userExists && user.assistant_name) ? user.assistant_name : 'Your Assistant';
let assistantEmoji = (userExists && user.assistant_emoji) ? user.assistant_emoji : ':robot_face:';

return [{
  json: {
    route, subRoute, userId, text,
    channelId: event.channelId,
    teamId: event.teamId,
    userRecord: userExists ? user : null,
    dbUserId: userExists ? user.id : null,
    organizationId: userExists ? user.organization_id : null,
    assistantName, assistantEmoji, state
  }
}];

