const data = $('Route by State').first().json;
const text = (data.text || '').trim();

// Strip presentation-related keywords from anywhere in the text
// to extract the actual prompt/topic
const prompt = text
  .replace(/\b(presentation|slide|slides|deck|create|make|generate|build|give\s+me|i\s+need|can\s+you|please|a|the)\b/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim();

return [{
  json: {
    ...data,
    presentationPrompt: prompt.length > 0 ? text : '',
    isValid: prompt.length > 0,
    responseText: prompt.length > 0 ? '' : data.assistantEmoji + ' Please include a description. Example:\n`presentation Build a Q1 engineering review`'
  }
}];

const input = $('Route by State').first().json;
const assistantName = input.assistantName;
const assistantEmoji = input.assistantEmoji;
const currentFocus = (input.userRecord && input.userRecord.focus) || 'revenue';

const rawText = (input.text || '').trim();
const focusArg = rawText.replace(/^focus\s*/i, '').trim().toLowerCase();

const focusMap = {
  'revenue': 'revenue', 'new logo': 'revenue', 'new business': 'revenue', 'sales': 'revenue', 'arr': 'revenue',
  'retention': 'retention', 'renew': 'retention', 'renewals': 'retention',
  'csm': 'retention', 'customer success': 'retention', 'cs': 'retention',
  'technical': 'technical', 'se': 'technical', 'solutions': 'technical', 'poc': 'technical', 'engineering': 'technical',
  'executive': 'executive', 'exec': 'executive', 'leadership': 'executive', 'strategic': 'executive', 'ceo': 'executive'
};

const focusLabels = {
  'revenue':   'Revenue — new logo & net new ARR',
  'retention': 'Retention — renewals & existing customers',
  'technical': 'Technical — POC stage & SE view',
  'executive': 'Executive — strategic portfolio overview'
};

let newFocus = null;
let needsUpdate = false;
let responseText = '';

if (!focusArg || focusArg === 'status' || focusArg === 'show' || focusArg === '?') {
  responseText = `Your current briefing focus is *${focusLabels[currentFocus] || currentFocus}*.\n\nChange it with:\n• \`focus revenue\` — new logo and net new ARR\n• \`focus retention\` — renewals and existing customers only\n• \`focus technical\` — POC stage and SE view\n• \`focus executive\` — strategic portfolio overview`;
} else {
  newFocus = focusMap[focusArg] || null;
  if (!newFocus) {
    responseText = `*"${focusArg}"* isn't a recognised focus. Options:\n• \`focus revenue\` — new logo and net new ARR\n• \`focus retention\` — renewals and existing customers only\n• \`focus technical\` — POC stage and SE view\n• \`focus executive\` — strategic portfolio overview`;
  } else if (newFocus === currentFocus) {
    responseText = `Your focus is already set to *${focusLabels[newFocus]}* — nothing to change.`;
  } else {
    needsUpdate = true;
    responseText = `Done. Your briefing focus is now *${focusLabels[newFocus]}*.\n\nType \`brief\` to generate a digest with your updated focus.`;
  }
}

return [{
  json: {
    userId: input.dbUserId,
    channelId: input.channelId,
    newFocus: newFocus || currentFocus,
    needsUpdate,
    responseText,
    assistantName,
    assistantEmoji
  }
}];

const orgId = $('Lookup Default Org').first().json.id;
