parameters.jsCode:
// Parse account name from meet command + build People.ai query
const data = $('Route by State').first().json;
const text = (data.text || '').trim();

// Strip command keywords to find the account name
const accountArg = text
  .replace(/\b(meet|meeting\s+brief|prep|prep\s+me\s+for|for|with|about|on|a|the|my|please)\b/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim();

if (!accountArg) {
  return [{ json: { ...data, hasAccount: false, responseText: 'What account should I prep you for? Try: `meet Five9` or `meet Dataiku`' } }];
}

const ur = data.userRecord || {};
const repName = (ur.email || '').split('@')[0].replace(/\./g, ' ').replace(/\b\w/g, c => c.toUpperCase()) || 'Rep';

// Build People.ai export query for meetings at this account in next 48h
const now = Date.now();
const twoDaysOut = now + 48 * 3600000;
const meetQuery = JSON.stringify({
  object: "activity",
  filter: {
    "$and": [
      { attribute: { slug: "ootb_activity_type" }, clause: { "$eq": "meeting" } },
      { attribute: { slug: "ootb_activity_external" }, clause: { "$eq": true } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$gte": now - 24 * 3600000 } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$lte": twoDaysOut } }
    ]
  },
  columns: [
    { slug: "ootb_activity_uid" },
    { slug: "ootb_activity_timestamp" },
    { slug: "ootb_activity_subject" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_email" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_name" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_external" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_job_title" },
    { slug: "ootb_activity_account" },
    { slug: "ootb_activity_opportunity" }
  ],
  sort: [
    { attribute: { slug: "ootb_activity_timestamp" }, direction: "asc" }
  ]
});

return [{ json: {
  ...data,
  hasAccount: true,
  accountName: accountArg,
  repName,
  meetQuery,
  meetInput: {
    userId: data.dbUserId,
    slackUserId: data.userId,
    email: ur.email || '',
    assistant_name: data.assistantName,
    assistant_emoji: data.assistantEmoji,
    assistant_persona: ur.assistant_persona || null,
    timezone: ur.timezone || 'America/Los_Angeles',
    repName,
    accountName: accountArg,
    meetingSubject: 'On-demand meeting prep: ' + accountArg,
    meetingTime: '',
    participants: '',
    opportunityName: '',
    opportunityStage: '',
    opportunityAmount: '',
    opportunityCloseDate: '',
    opportunityEngagement: '',
    activityUid: 'ondemand_' + Date.now()
  }
} }];

// Parse People.ai participant CSV and enrich meetInput
const data = $('Parse Meet Account').first().json;
const meetInput = { ...data.meetInput };
const accountName = (data.accountName || '').toLowerCase();

// Get the CSV from Fetch Meet Participants
const raw = $('Fetch Meet Participants').first().json;
const csvData = typeof raw === 'string' ? raw : (raw.data || raw.body || '');

if (!csvData || typeof csvData !== 'string') {
  // No participant data — proceed without it
  return [{ json: meetInput }];
}

function parseCsvLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  let inBrackets = 0;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '[') inBrackets++;
    else if (ch === ']') inBrackets--;
    if (ch === '"') {
      if (inQuotes && i + 1 < line.length && line[i + 1] === '"') {
        current += '"'; i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (ch === ',' && !inQuotes && inBrackets === 0) {
      result.push(current.trim());
      current = '';
    } else {
      current += ch;
    }
  }
  result.push(current.trim());
  return result;
}

function parseList(val) {
  if (!val) return [];
  return val.replace(/^\[/, '').replace(/\]$/, '').trim().split(';').map(s => s.trim());
}

const lines = csvData.split(/\r?\n/).filter(l => l.trim());
if (lines.length < 2) {
  return [{ json: meetInput }];
}

const headers = parseCsvLine(lines[0]);
const headerMap = {};
headers.forEach((h, i) => { headerMap[h.toLowerCase()] = i; });

function getField(row, ...names) {
  for (const name of names) {
    const idx = headerMap[name.toLowerCase()];
    if (idx !== undefined && row[idx]) return row[idx];
  }
  return '';
}

// Find meetings matching this account
const now = Date.now();
let bestMatch = null;
let bestDiff = Infinity;

for (let i = 1; i < lines.length; i++) {
  const row = parseCsvLine(lines[i]);
  if (row.length < 2) continue;

  const acct = getField(row, 'Account (name)', 'Account');
  if (!acct) continue;

  // Fuzzy account matching
  const acctLower = acct.toLowerCase();
  const inputLower = accountName.toLowerCase();

  let isMatch = false;
  if (acctLower === inputLower) isMatch = true;
  else if (acctLower.startsWith(inputLower)) isMatch = true;
  else if (inputLower.startsWith(acctLower)) isMatch = true;
  else if (new RegExp('\\b' + inputLower.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'i').test(acct)) isMatch = true;
  else if (acctLower.includes(inputLower)) isMatch = true;
  else {
    const inputWords = inputLower.split(/\s+/);
    const matched = inputWords.filter(w => acctLower.includes(w));
    if (matched.length > 0 && matched.length >= inputWords.length * 0.5) isMatch = true;
  }

  if (!isMatch) continue;

  const timestampStr = getField(row, 'Activity date');
  const ts = timestampStr ? new Date(timestampStr).getTime() : 0;

  // Prefer the nearest upcoming meeting
  const diff = ts - now;
  if (diff > -3600000 && diff < bestDiff) { // Allow 1hr past meetings too
    bestDiff = diff;
    bestMatch = {
      subject: getField(row, 'Subject') || 'Customer Meeting',
      timestamp: ts,
      timestampStr,
      activityUid: getField(row, 'Activity'),
      emails: parseList(getField(row, 'Activity Participants (Email)')),
      names: parseList(getField(row, 'Activity Participants (Name)')),
      externals: parseList(getField(row, 'Activity Participants (External)')),
      titles: parseList(getField(row, 'Activity Participants (Job Title)')),
      oppName: getField(row, 'Opportunity (name)', 'Opportunity'),
      accountName: getField(row, 'Account (name)', 'Account'),
    };
  }
}

if (bestMatch) {
  // Build a formatted participant string for the agent
  const parts = [];
  for (let p = 0; p < bestMatch.emails.length; p++) {
    const isExternal = (bestMatch.externals[p] || '').toLowerCase() === 'true';
    const name = bestMatch.names[p] || bestMatch.emails[p];
    const title = bestMatch.titles[p] || '';
    const tag = isExternal ? 'external' : 'internal';
    parts.push(`${name} (${tag}${title ? ', ' + title : ''}) <${bestMatch.emails[p]}>`);
  }

  meetInput.participants = parts.join('; ');
  meetInput.meetingSubject = bestMatch.subject;
  meetInput.meetingTime = String(bestMatch.timestamp);
  meetInput.accountName = bestMatch.accountName || data.accountName;
  if (bestMatch.oppName) meetInput.opportunityName = bestMatch.oppName;
  if (bestMatch.activityUid) meetInput.activityUid = bestMatch.activityUid;
}

return [{ json: meetInput }];
